/* eslint-disable no-param-reassign */
import type { SudokuBoard } from '@algorithm.ts/sudoku'
import {
  SudokuCreator,
  copySudokuBoard,
  createSegmentCodeMap,
  createSudokuBoard,
} from '@algorithm.ts/sudoku'
import { useMemo } from 'react'
import type { SudokuGameData } from '../types'

const sudokuCreatorMap: Record<number, SudokuCreator> = {}

/**
 *
 * @param SUDOKU_SIZE_SQRT
 * @param difficulty
 * @param gameTick
 * @returns
 */
export function useSudokuGameData(
  SUDOKU_SIZE_SQRT: number,
  difficulty?: number,
  gameTick?: number,
): SudokuGameData {
  const result = useMemo<SudokuGameData>((): SudokuGameData => {
    const SUDOKU_SIZE = SUDOKU_SIZE_SQRT * SUDOKU_SIZE_SQRT
    let creator = sudokuCreatorMap[SUDOKU_SIZE]
    if (creator === undefined) {
      creator = new SudokuCreator({ childMatrixSize: SUDOKU_SIZE_SQRT })
      sudokuCreatorMap[SUDOKU_SIZE] = creator
    }

    // Create a initial attempt.
    const { puzzle, solution } = creator.createSudoku(difficulty)
    const attempt: SudokuBoard = createSudokuBoard(SUDOKU_SIZE)
    copySudokuBoard(puzzle, attempt)

    const segmentNoMap: number[] = createSegmentCodeMap(SUDOKU_SIZE_SQRT)
    const duplicatedMap: boolean[][] = new Array(SUDOKU_SIZE)
    for (let r = 0; r < SUDOKU_SIZE; ++r) {
      duplicatedMap[r] = new Array(SUDOKU_SIZE).fill(false)
    }

    return {
      SUDOKU_SIZE,
      SUDOKU_SIZE_SQRT,
      puzzle,
      solution,
      attempt,
      segmentNoMap,
      duplicatedMap,
    }
  }, [gameTick, difficulty, SUDOKU_SIZE_SQRT])
  return result
}

export default useSudokuGameData
